def findSubsequenceCount(S, T):
    m, n = len(T), len(S)
    if m > n:
        return 0
    mat = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(1, m + 1):
        mat[i][0] = 0
    for j in range(n + 1):
        mat[0][j] = 1
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if T[i - 1] != S[j - 1]:
                mat[i][j] = mat[i][j - 1]
            else:
                mat[i][j] = mat[i][j - 1] + mat[i - 1][j - 1]
    return mat[m][n]

