    while i < len(string):
        count = 0
        if '0' <= string[i] <= '9':
            while '0' <= string[i] <= '9':
                count = count * 10 + int(string[i])
                i += 1
            i -= 1
            integer_stack.append(count)
        elif string[i] == ']':
            temp = ""
            count = 0
            if integer_stack:
                count = integer_stack.pop()
            while string_stack and string_stack[-1] != '[':
                temp = string_stack.pop() + temp
            if string_stack and string_stack[-1] == '[':
                string_stack.pop()
            result = ""
            for _ in range(count):
                result += temp
            for char in result:
                string_stack.append(char)
            result = ""
        elif string[i] == '[':
            if i > 0 and '0' <= string[i-1] <= '9':
                string_stack.append(string[i])
